def smith_waterman(seq1, seq2):
    M = [[0] * (len(seq2) + 1) for _ in range(len(seq1) + 1)]
    max_local = 0
    for i, a in enumerate(seq1):
        for j, b in enumerate(seq2):
            if a.upper() == b.upper():
                score = M[i-1][j-1] + (2 if a.upper() == b.upper() else -1)
            else:
                score = M[i-1][j-1] + (-1)
            gap_up = M[i][j-1] + (-1)
            gap_left = M[i-1][j] + (-1)
            M[i][j] = max(0, score, gap_up, gap_left)
            max_local = max(max_local, M[i][j])
    return max_local

